module top_module(d,clk,clrn,q
    );input [1:0] d;
	 input clk,clrn;
	 output [1:0] q;
    reg [1:0] q;
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or negedge clrn or posedge dbg_halt) begin
			if (clrn == 0) q <= 0;
			else				q <= d;
	 end	 
endmodule
